class Trie:
    def __init__(self): self.ch={}; self.end=False
    def insert(self, w):
        n=self
        for c in w:
            if c not in n.ch: n.ch[c]=Trie()
            n=n.ch[c]
        n.end=True
    def search(self, w):
        n=self._find(w)
        return n and n.end
    def starts_with(self, p): return self._find(p) is not None
    def _find(self, p):
        n=self
        for c in p:
            if c not in n.ch: return None
            n=n.ch[c]
        return n

