import functools, time
def retry(n=3, d=1):
    def deco(f):
        @functools.wraps(f)
        def w(*a, **k):
            for i in range(n):
                try: return f(*a, **k)
                except:
                    if i==n-1: raise
                    time.sleep(d)
        return w
    return deco

