import threading, collections
class BoundedBuffer:
    def __init__(s, cap): s.q=collections.deque(); s.cap=cap; s.lock=threading.Lock(); s.not_full=threading.Condition(s.lock); s.not_empty=threading.Condition(s.lock)
    def put(s, item):
        with s.not_full:
            while len(s.q)>=s.cap: s.not_full.wait()
            s.q.append(item); s.not_empty.notify()
    def get(s):
        with s.not_empty:
            while not s.q: s.not_empty.wait()
            item=s.q.popleft(); s.not_full.notify()
            return item

def caesar(text, shift):
    r = []
    for c in text:
        if c.isalpha():
            base = ord('A') if c.isupper() else ord('a')
            r.append(chr((ord(c)-base+shift)%26+base))
        else: r.append(c)
    return ''.join(r)

